import { Container, Box, Typography, Link, Grid } from '@material-ui/core';

const Contact = () => {
    return (
        <div>
            <Container className="contact" maxWidth="lg">
                <Box my={10}>
                    <Typography variant="h3" align="left" gutterBottom>
                        Contact
                    </Typography>
                    <Grid container>
                        <Grid item xs={4}>
                        <Typography variant="button" display="block" align="left" gutterBottom>
                            Phone
                        </Typography>
                        <Typography variant="h6" align="left" gutterBottom>
                            +886 961 100 735
                        </Typography>
                        </Grid>
                        <Grid item xs={4}>
                        <Typography variant="button" display="block" align="left" gutterBottom>
                            Email
                        </Typography>
                        <Typography variant="h6" align="left" gutterBottom>
                            ervsml@gmail.com
                        </Typography>
                        </Grid>
                        <Grid item xs={4}>
                        <Typography variant="button" display="block" align="left" gutterBottom>
                            LinkedIn
                        </Typography>
                        <Typography variant="h6" align="left" gutterBottom>
                            <Link href="https://www.linkedin.com/in/ervinsamuel/" target="_blank" color="inherit">
                                linkedin.com/in/ervinsamuel/
                            </Link>
                        </Typography>
                        </Grid>
                        <Grid item xs={4}>
                        <Typography variant="button" display="block" align="left" gutterBottom>
                            GitHub
                        </Typography>
                        <Typography variant="h6" align="left" gutterBottom>
                            <Link href="https://github.com/ervsam" target="_blank" color="inherit">
                                github.com/ervsam
                            </Link>
                        </Typography>
                        
                        </Grid>
                    </Grid>
                </Box>
            </Container>
        </div>
    )
}

export default Contact
